import pandas as pd
import time
import io

# Simulate a large transactions CSV in memory
def make_transactions_csv(n_rows=2_000_000):
    import numpy as np
    np.random.seed(42)
    merchants = [f'merchant_{i}' for i in range(1000)]
    data = {
        'txn_id': range(n_rows),
        'merchant': np.random.choice(merchants, n_rows),
        'amount': np.random.exponential(85, n_rows).round(2)
    }
    return pd.DataFrame(data)

# Approach 1: load all at once — fast but memory-intensive
def sum_by_merchant_all_at_once(df):
    return df.groupby('merchant')['amount'].sum().sort_values(ascending=False)

# Approach 2: chunked processing — constant memory footprint
def sum_by_merchant_chunked(df, chunksize=200_000):
    totals = {}
    for start in range(0, len(df), chunksize):
        chunk = df.iloc[start:start+chunksize]
        for merchant, amount in chunk.groupby('merchant')['amount'].sum().items():
            totals[merchant] = totals.get(merchant, 0) + amount
    return pd.Series(totals).sort_values(ascending=False)

df = make_transactions_csv(2_000_000)

t0 = time.time()
result1 = sum_by_merchant_all_at_once(df)
print(f'All-at-once:  {time.time()-t0:.2f}s  |  Top merchant: ${result1.iloc[0]:,.0f}')

t0 = time.time()
result2 = sum_by_merchant_chunked(df)
print(f'Chunked:      {time.time()-t0:.2f}s  |  Top merchant: ${result2.iloc[0]:,.0f}')
print('\nChunked approach uses fixed ~200MB RAM regardless of total file size')
